<template>
<NavigationComponent />
    <main style="min-height:100vh">
    <div class="container">
        <div class="row mt-5">
            <div class="col">
                <router-link :to="{name:'ppdb.index'}" class="btn btn-primary px-5 py-3"><i class="bi bi-house"></i> Home</router-link>
            </div>
        </div>
         <!-- v-for="alias in berita" :key="alias.id" -->
        <div  class="col">
            <div class="row text-center mt-5">
                <div class="col-md-12 mb-3">
                    <h1>{{ berita.judul}}</h1>
                            <img v-bind:src="'http://wawanindrawan.nurulfikri.com/capstone-km/'+berita.thumbnail" class="img-fluid shadow-md" style="width:40%;background:#eaeaea">

                </div>
                <div class="col-md-12">
                    <span class="mx-3"><i class="bi bi-calendar3"></i> {{ berita.tanggal }}</span>
                </div>
            </div>
            <div class="row p-3">
                <div class="col-md-12">
                    <p>{{ berita.isi }}</p>
                </div>
            </div>
        </div>

    </div>
    </main>
<FooterComponent />
</template>
<script>
import NavigationComponent from '../../components/NavigationComponent.vue';
import FooterComponent from '../../components/FooterComponent.vue';

import axios from 'axios'
import { onMounted, ref } from 'vue';
import { useRoute } from 'vue-router'
export default{
    setup(){
        // reactive state
        let berita = ref([]);
        const route = useRoute();

            console.log(route.params.id);
        onMounted(()=>{
            axios.get(`http://wawanindrawan.nurulfikri.com/capstone-km/api/berita/detail/${route.params.id}`)
                .then((result) => {
                    berita.value = result.data.berita
                }).catch((err) => {
                    console.log(err.response)
                });
        });
        return {
            berita
        }
    },

    name: "ArtikelView",
    components: { NavigationComponent, FooterComponent },
   
}
</script>